/**
 * @summary Sandbox join QR code
 */
export const getWhatsappQrCodeUrl = () => {
  return `/api/counsel/whatsapp/qrcode`;
};

export const whatsappQrCode = async (options?: RequestInit): Promise<Blob> => {
  return customFetch<Blob>(getWhatsappQrCodeUrl(), {
    ...options,
    method: "GET",
  });
};

export const getWhatsappQrCodeQueryKey = () => {
  return [`/api/counsel/whatsapp/qrcode`] as const;
};

export const getWhatsappQrCodeQueryOptions = <
  TData = Awaited<ReturnType<typeof whatsappQrCode>>,
  TError = ErrorType<unknown>,
>(options?: {
  query?: UseQueryOptions<
    Awaited<ReturnType<typeof whatsappQrCode>>,
    TError,
    TData
  >;
  request?: SecondParameter<typeof customFetch>;
}) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey = queryOptions?.queryKey ?? getWhatsappQrCodeQueryKey();

  const queryFn: QueryFunction<Awaited<ReturnType<typeof whatsappQrCode>>> = ({
    signal,
  }) => whatsappQrCode({ signal, ...requestOptions });

  return { queryKey, queryFn, ...queryOptions } as UseQueryOptions<
    Awaited<ReturnType<typeof whatsappQrCode>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type WhatsappQrCodeQueryResult = NonNullable<
  Awaited<ReturnType<typeof whatsappQrCode>>
>;
export type WhatsappQrCodeQueryError = ErrorType<unknown>;

/**
 * @summary Sandbox join QR code
 */

export function useWhatsappQrCode<
  TData = Awaited<ReturnType<typeof whatsappQrCode>>,
  TError = ErrorType<unknown>,
>(options?: {
  query?: UseQueryOptions<
    Awaited<ReturnType<typeof whatsappQrCode>>,
    TError,
    TData
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseQueryResult<TData, TError> & { queryKey: QueryKey } {
  const queryOptions = getWhatsappQrCodeQueryOptions(options);

  const query = useQuery(queryOptions) as UseQueryResult<TData, TError> & {
    queryKey: QueryKey;
  };

  return { ...query, queryKey: queryOptions.queryKey };
}
